// ============================================================
// SYNTHELIX SURGE TIERING ENGINE
// ============================================================
// Calculates weighted patient load, capacity ratio, and tier.
// Does NOT draft the SBAR — that's the AI Agent's job.
// ============================================================

const CONFIG = {
  staffed_capacity: 30,
  resus_bays: 4,
  green_threshold: 0.80,
  amber_threshold: 0.90,
  red_threshold: 1.10,
  cat1_weight: 3.0,
  cat2_weight: 2.0,
  cat3_weight: 1.0,
  cat4_weight: 0.5,
  cat5_weight: 0.3,
  resus_spike_threshold: 2,
  forecast_window_hours: 4,
};

const vtp = $input.first().json;

const predicted_arrivals = {
  cat1: vtp.predicted_cat1 || 0,
  cat2: vtp.predicted_cat2 || 0,
  cat3: vtp.predicted_cat3 || 0,
  cat4: vtp.predicted_cat4 || 0,
  cat5: vtp.predicted_cat5 || 0,
};

const current_occupancy_pct = vtp.current_occupancy_pct || 0;
const current_patients = vtp.current_patients || 0;
const departure_rate = vtp.predicted_departures || 0;
const timestamp = vtp.timestamp || new Date().toISOString();

const total_raw = predicted_arrivals.cat1 + predicted_arrivals.cat2 + predicted_arrivals.cat3 + predicted_arrivals.cat4 + predicted_arrivals.cat5;
const weighted_load = (predicted_arrivals.cat1 * CONFIG.cat1_weight) + (predicted_arrivals.cat2 * CONFIG.cat2_weight) + (predicted_arrivals.cat3 * CONFIG.cat3_weight) + (predicted_arrivals.cat4 * CONFIG.cat4_weight) + (predicted_arrivals.cat5 * CONFIG.cat5_weight);
const net_pressure = weighted_load - departure_rate;
const capacity_ratio = net_pressure / CONFIG.staffed_capacity;
const resus_spike = predicted_arrivals.cat1 >= CONFIG.resus_spike_threshold;

let surge_tier = 'NORMAL';
let surge_level = 0;
let tier_rationale = [];

if (capacity_ratio >= CONFIG.red_threshold) {
  surge_tier = 'RED'; surge_level = 3;
  tier_rationale.push(`Capacity ratio ${(capacity_ratio*100).toFixed(0)}% exceeds RED threshold (${CONFIG.red_threshold*100}%)`);
} else if (capacity_ratio >= CONFIG.amber_threshold) {
  surge_tier = 'AMBER'; surge_level = 2;
  tier_rationale.push(`Capacity ratio ${(capacity_ratio*100).toFixed(0)}% exceeds AMBER threshold (${CONFIG.amber_threshold*100}%)`);
} else if (capacity_ratio >= CONFIG.green_threshold) {
  surge_tier = 'GREEN'; surge_level = 1;
  tier_rationale.push(`Capacity ratio ${(capacity_ratio*100).toFixed(0)}% exceeds GREEN threshold (${CONFIG.green_threshold*100}%)`);
} else {
  tier_rationale.push(`Capacity ratio ${(capacity_ratio*100).toFixed(0)}% within normal parameters`);
}

if (resus_spike && surge_level < 2) {
  const prev = surge_tier;
  surge_tier = 'AMBER'; surge_level = 2;
  tier_rationale.push(`ESCALATED from ${prev}: ${predicted_arrivals.cat1} Cat 1 patients — resus spike (≥${CONFIG.resus_spike_threshold})`);
}
if (current_occupancy_pct > 85 && surge_level < 3) {
  tier_rationale.push(`WARNING: ED occupancy ${current_occupancy_pct}% — reduced buffer`);
}

return [{
  json: {
    surge_tier, surge_level, tier_rationale, timestamp,
    metrics: {
      total_raw_arrivals: total_raw,
      weighted_load: +weighted_load.toFixed(1),
      net_pressure: +net_pressure.toFixed(1),
      capacity_ratio_pct: +(capacity_ratio*100).toFixed(1),
      current_occupancy_pct,
      current_patients,
      predicted_departures: departure_rate,
      resus_spike,
    },
    predicted_arrivals,
    config_snapshot: {
      staffed_capacity: CONFIG.staffed_capacity,
      green_pct: CONFIG.green_threshold*100,
      amber_pct: CONFIG.amber_threshold*100,
      red_pct: CONFIG.red_threshold*100,
      window_hrs: CONFIG.forecast_window_hours,
    },
    requires_notification: surge_level >= 1,
    requires_approval: surge_level >= 2,
    requires_full_escalation: surge_level >= 3,
  }
}];

// ── Prepare the AI Agent prompt with all surge data ─────────
// This node formats the surge data into a structured prompt
// that the AI Agent will use to draft the SBAR briefing.

const item = $input.first().json;
const isRed = item.surge_tier === 'RED';

const agentPrompt = `You are the Synthelix Coordination Co-pilot. A surge has been detected in the Emergency Department.

Using the data below, draft a complete SBAR (Situation-Background-Assessment-Recommendation) clinical briefing for the ED Charge Nurse.

--- SURGE DATA ---
Surge Tier: ${item.surge_tier} (Level ${item.surge_level})
Timestamp: ${item.timestamp}
Capacity Ratio: ${item.metrics.capacity_ratio_pct}% of staffed capacity (${item.config_snapshot.staffed_capacity} patients)

Predicted Arrivals (next ${item.config_snapshot.window_hrs} hours):
- Cat 1 (Immediate/Resuscitation): ${item.predicted_arrivals.cat1}
- Cat 2 (Very Urgent): ${item.predicted_arrivals.cat2}
- Cat 3 (Urgent): ${item.predicted_arrivals.cat3}
- Cat 4 (Standard): ${item.predicted_arrivals.cat4}
- Cat 5 (Non-Urgent): ${item.predicted_arrivals.cat5}
- Total raw arrivals: ${item.metrics.total_raw_arrivals}
- Weighted capacity load: ${item.metrics.weighted_load}

Current ED State:
- Occupancy: ${item.metrics.current_occupancy_pct}% (${item.metrics.current_patients} patients currently in department)
- Predicted departures in window: ${item.metrics.predicted_departures}
- Net capacity pressure: ${item.metrics.net_pressure}
- Resuscitation spike detected: ${item.metrics.resus_spike ? 'YES — ' + item.predicted_arrivals.cat1 + ' Cat 1 patients predicted' : 'No'}

Tiering Rationale: ${item.tier_rationale.join('; ')}

--- INSTRUCTIONS ---
Draft the SBAR using this exact structure:

**SITUATION:** One paragraph. State the alert tier, when it was triggered, the headline numbers (total arrivals, weighted load vs capacity), and the urgency level. Be direct and clinical.

**BACKGROUND:** One paragraph. Provide context: current ED occupancy, the acuity breakdown of predicted arrivals, departure rate, and any compounding factors (e.g., high occupancy reducing buffer, resus spike).

**ASSESSMENT:** One paragraph. Explain WHY this tier was triggered. Reference the capacity ratio, any threshold breaches, and whether a resus spike contributed. State what the key risk is (e.g., "resus bay saturation", "corridor care", "ambulance queuing").

**RECOMMENDATION:** A numbered list of specific, actionable steps appropriate for ${item.surge_tier} level. ${isRed ? 'This is a CRITICAL surge — include full escalation actions: elective cancellation, ambulance diversion consideration, overflow activation, and executive notification.' : 'Include preparation actions: ICU/bed management alerts, on-call standby, elective review, and discharge list review.'}
${item.metrics.resus_spike ? 'IMPORTANT: Include a specific recommendation about securing resus bay availability and senior clinician cover for the predicted Cat 1 patients.' : ''}

Keep the language clinical, concise, and NHS-appropriate. Do not use jargon the Charge Nurse wouldn't recognise. This will be sent as an official briefing for review and approval — mark it clearly as a DRAFT.

End with: "--- This SBAR was auto-drafted by Synthelix. All actions require Charge Nurse approval before execution. ---"`;

return [{
  json: {
    ...item,
    agentPrompt,
    approval_requested_at: new Date().toISOString(),
  }
}];

// ── Combine AI-drafted SBAR with surge data ─────────────────
// The Agent outputs the SBAR text. We package it with the
// original metrics for the approval email.

const agentOutput = $input.first().json;
const surgeData = $('Prepare Agent Prompt').first().json;

// The agent's response contains the drafted SBAR
const sbar_drafted = agentOutput.output || agentOutput.text || 'SBAR draft unavailable — agent returned no output.';

const icon = surgeData.surge_tier === 'RED' ? '🔴' : '🟠';
const tierLabel = surgeData.surge_tier === 'RED' ? 'CRITICAL SURGE' : 'SURGE ALERT';

// Build HTML email subject with surge tier and level
const emailSubject = `${icon} SYNTHELIX ${tierLabel} [${surgeData.surge_tier} - Level ${surgeData.surge_level}] — Approval Required`;

// Convert the SBAR markdown-ish text to HTML paragraphs with proper formatting
const sbar_clean = sbar_drafted.replace(/\*\*DRAFT SBAR[^\n]*\*\*\n?/gi, '').trim();
const sbar_html = sbar_clean
  .replace(/\*\*SITUATION:\*\*/gi, '<h3 style="color:#333;border-bottom:2px solid #eee;padding-bottom:8px;margin-top:16px;">SITUATION</h3>')
  .replace(/\*\*BACKGROUND:\*\*/gi, '<h3 style="color:#333;border-bottom:2px solid #eee;padding-bottom:8px;margin-top:16px;">BACKGROUND</h3>')
  .replace(/\*\*ASSESSMENT:\*\*/gi, '<h3 style="color:#333;border-bottom:2px solid #eee;padding-bottom:8px;margin-top:16px;">ASSESSMENT</h3>')
  .replace(/\*\*RECOMMENDATION:\*\*/gi, '<h3 style="color:#333;border-bottom:2px solid #eee;padding-bottom:8px;margin-top:16px;">RECOMMENDATION</h3>')
  .replace(/\n\n/g, '</p><p style="margin:8px 0;line-height:1.6;">')
  .replace(/\n(\d+\.)/g, '<br>$1')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\n(?!\n)/g, '<br>');

// Build full HTML email body with complete SBAR report
const emailBody = `<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">
  <div style="background:${surgeData.surge_tier === 'RED' ? '#D32F2F' : '#F57C00'};color:white;padding:16px 24px;border-radius:8px 8px 0 0;">
    <h2 style="margin:0;">${icon} SYNTHELIX ${tierLabel}</h2>
    <p style="margin:4px 0 0;opacity:0.9;">Level ${surgeData.surge_level} | Capacity: ${surgeData.metrics.capacity_ratio_pct}% | ${new Date(surgeData.timestamp).toLocaleString('en-GB')}</p>
  </div>
  <div style="border:1px solid #ddd;border-top:none;padding:24px;border-radius:0 0 8px 8px;">
    <div style="background:#FFF3E0;border-left:4px solid #F57C00;padding:12px 16px;margin-bottom:20px;border-radius:0 4px 4px 0;">
      <strong>⚠️ This SBAR was drafted by the Synthelix AI Agent.</strong> Please review carefully before approving distribution.
    </div>
    <div style="background:#f9f9f9;padding:20px;border-radius:6px;margin-bottom:20px;">
      <p style="margin:8px 0;line-height:1.6;">${sbar_html}</p>
    </div>
    <div style="background:#E3F2FD;border-left:4px solid #1976D2;padding:12px 16px;margin-bottom:20px;border-radius:0 4px 4px 0;">
      <strong>📝 Need to modify?</strong> Click <strong>Reject</strong> and reply to this email with your changes. The system will log your rejection and you can manually coordinate the response.
    </div>
    <p style="color:#999;font-size:12px;text-align:center;">Synthelix AI Agent draft | Audit ID: ${$execution.id} | Config: capacity=${surgeData.config_snapshot.staffed_capacity}, amber=${surgeData.config_snapshot.amber_pct}%, red=${surgeData.config_snapshot.red_pct}%</p>
  </div>
</body></html>`;

return [{
  json: {
    to: 'haifaalarafa@gmail.com',
    subject: emailSubject,
    html: emailBody,
    // Store all surge data for merge node to access later
    ...surgeData,
    sbar_drafted,
    execution_id: $execution.id,
    approval_requested_at: new Date().toISOString()
  }
}];

const waitData = $input.first().json;
const surgeData = $('Build Approval Email').first().json;

// Gmail wait node returns 'approved' field (true/false)
const approved = waitData.data.approved;
const decision = approved === true ? 'APPROVED' : 'REJECTED';

const nurse_id = waitData.to || 'charge_nurse_01';
const decision_timestamp = new Date().toISOString();

return [{
  json: {
    decision, 
    nurse_id, 
    decision_timestamp,
    response_time_seconds: Math.round(
      (new Date(decision_timestamp) - new Date(surgeData.approval_requested_at)) / 1000
    ),
    surge_tier: surgeData.surge_tier,
    surge_level: surgeData.surge_level,
    sbar_drafted: surgeData.sbar_drafted,
    metrics: surgeData.metrics,
    predicted_arrivals: surgeData.predicted_arrivals,
    escalation_targets: surgeData.surge_level >= 3
      ? ['Site Manager','Clinical Director','ICU Lead','Bed Management','Surgical Team Lead','Ambulance Liaison','On-Call Coordinator']
      : ['ICU Lead','Bed Management','On-Call Coordinator'],
    config_snapshot: surgeData.config_snapshot,
    execution_id: surgeData.execution_id,
    original_timestamp: surgeData.timestamp,
  }
}];

// ── APPROVED: Build dept-specific distribution messages ──────
const item = $input.first().json;
const isRed = item.surge_level >= 3;

const distributions = item.escalation_targets.map(target => {
  let action = '';
  switch(target) {
    case 'ICU Lead': action = `Expedite ${Math.min(item.predicted_arrivals.cat1+1,3)} discharges. Prepare for ED transfers. ${item.predicted_arrivals.cat1} Cat 1 patients predicted.`; break;
    case 'Bed Management': action = `Occupancy ${item.metrics.current_occupancy_pct}%. ${item.metrics.total_raw_arrivals} arrivals predicted. Identify ${Math.ceil(item.metrics.total_raw_arrivals*0.3)} available beds.`; break;
    case 'Surgical Team Lead': action = isRed ? 'Initiate elective cancellation. Postpone non-urgent cases first.' : 'Review elective list for potential postponements.'; break;
    case 'On-Call Coordinator': action = isRed ? 'Activate all on-call staff. Deploy to ED + overflow.' : 'Place on-call on standby for early call-in within 30 mins.'; break;
    case 'Site Manager': action = `Level ${item.surge_level} surge. ED at ${item.metrics.current_occupancy_pct}%. Charge Nurse approved full escalation.`; break;
    case 'Clinical Director': action = `Critical surge Level ${item.surge_level}. Capacity ratio: ${item.metrics.capacity_ratio_pct}%. Full escalation approved.`; break;
    case 'Ambulance Liaison': action = `ED at/exceeding capacity. Consider diversion for non-critical. Occupancy: ${item.metrics.current_occupancy_pct}%. Cat 1 predicted: ${item.predicted_arrivals.cat1}.`; break;
    default: action = `Surge Level ${item.surge_level} active. Await instructions.`;
  }
  return { recipient: target, action, priority: isRed ? 'CRITICAL' : 'HIGH' };
});

return [{ json: {
  action: 'DISTRIBUTE_APPROVED',
  approved_by: item.nurse_id, approved_at: item.decision_timestamp,
  response_time_seconds: item.response_time_seconds,
  surge_tier: item.surge_tier, surge_level: item.surge_level,
  sbar_drafted: item.sbar_drafted,
  distributions,
  audit: {
    execution_id: item.execution_id, surge_detected_at: item.original_timestamp,
    decision: 'APPROVED', approved_by: item.nurse_id, approved_at: item.decision_timestamp,
    response_time_seconds: item.response_time_seconds,
    tier: item.surge_tier, config: item.config_snapshot,
    distributions_count: distributions.length,
  }
} }];

// ── AMBER Pathway: Build individual targeted emails ──────────
// Recipients: ICU Lead, Bed Management, On-Call Coordinator
const item = $input.first().json;
const m = item.metrics || {};
const p = item.predicted_arrivals || {};
const approvedAt = item.approved_at ? new Date(item.approved_at).toLocaleString('en-GB') : new Date().toLocaleString('en-GB');
const auditId = item.audit ? item.audit.execution_id : 'N/A';

const emailDirectory = {
  'ICU Lead': 'icu.lead@rwh.nhs.uk',
  'Bed Management': 'bed.management@rwh.nhs.uk',
  'On-Call Coordinator': 'oncall.coordinator@rwh.nhs.uk',
};

const items = item.distributions.map(d => {
  const recipientEmail = emailDirectory[d.recipient] || 'haifaalarafa@gmail.com';

  const emailHtml = '<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:0;background:#f4f4f4;">'
    + '<div style="background:#F57C00;color:white;padding:20px 28px;border-radius:8px 8px 0 0;">'
    + '<h2 style="margin:0;font-size:20px;letter-spacing:0.5px;">&#x1F7E0; SYNTHELIX SURGE ALERT &#x2014; AMBER</h2>'
    + '<p style="margin:6px 0 0;opacity:0.9;font-size:13px;">Level 2 | Capacity: ' + (m.capacity_ratio_pct || 'N/A') + '% | ' + approvedAt + '</p>'
    + '</div>'

    + '<div style="background:white;border:1px solid #ddd;border-top:none;padding:28px;border-radius:0 0 8px 8px;">'

    // Action box
    + '<div style="background:#FFF3E0;border-left:5px solid #F57C00;padding:18px 20px;margin-bottom:24px;border-radius:0 6px 6px 0;">'
    + '<p style="margin:0 0 4px;font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#E65100;font-weight:bold;">Action Required</p>'
    + '<h3 style="margin:0 0 10px;color:#BF360C;font-size:18px;">' + d.recipient + '</h3>'
    + '<p style="margin:0;font-size:15px;line-height:1.7;color:#333;">' + d.action + '</p>'
    + '</div>'

    // Metrics table
    + '<table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:24px;">'
    + '<tr style="background:#F57C00;color:white;"><td colspan="2" style="padding:10px 14px;font-weight:bold;font-size:13px;text-transform:uppercase;letter-spacing:0.5px;border-radius:4px 4px 0 0;">Key Metrics</td></tr>'
    + '<tr style="background:#FFF8E1;"><td style="padding:10px 14px;color:#555;border-bottom:1px solid #FFE0B2;">Predicted Arrivals</td><td style="padding:10px 14px;font-weight:bold;border-bottom:1px solid #FFE0B2;">' + (m.total_raw_arrivals || 0) + ' total (Weighted load: ' + (m.weighted_load || 0) + ')</td></tr>'
    + '<tr><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Cat 1 &#x2014; Resuscitation</td><td style="padding:10px 14px;font-weight:bold;border-bottom:1px solid #f0f0f0;">' + (p.cat1 || 0) + '</td></tr>'
    + '<tr style="background:#fafafa;"><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Cat 2 &#x2014; Very Urgent</td><td style="padding:10px 14px;font-weight:bold;border-bottom:1px solid #f0f0f0;">' + (p.cat2 || 0) + '</td></tr>'
    + '<tr><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Current ED Occupancy</td><td style="padding:10px 14px;font-weight:bold;border-bottom:1px solid #f0f0f0;">' + (m.current_occupancy_pct || 0) + '%</td></tr>'
    + '<tr style="background:#FFF3E0;"><td style="padding:10px 14px;color:#555;">Priority Level</td><td style="padding:10px 14px;font-weight:bold;color:#F57C00;font-size:15px;">' + d.priority + '</td></tr>'
    + '</table>'

    // Approval stamp
    + '<div style="background:#E8F5E9;border-left:4px solid #4CAF50;padding:12px 16px;margin-bottom:20px;border-radius:0 4px 4px 0;">'
    + '<p style="margin:0;font-size:13px;color:#2E7D32;">&#x2705; <strong>Approved by:</strong> ' + (item.approved_by || 'ED Charge Nurse') + ' at ' + approvedAt + '</p>'
    + '</div>'

    // Footer
    + '<p style="color:#aaa;font-size:11px;text-align:center;margin:0;padding-top:12px;border-top:1px solid #eee;">Synthelix Surge Co-pilot v3 | Audit ID: ' + auditId + ' | Escalation approved by ED Charge Nurse before distribution</p>'
    + '</div>'
    + '</body></html>';

  return {
    json: {
      to: recipientEmail,
      subject: '\u{1F7E0} SURGE ALERT [AMBER] \u2014 Action Required: ' + d.recipient,
      html: emailHtml,
      recipient_role: d.recipient,
      action: d.action,
      priority: d.priority,
      surge_tier: 'AMBER',
    }
  };
});

return items;

// ── RED Pathway: Build individual targeted emails ────────────
// Recipients: Full 7-role escalation chain
// Senior leadership (Site Manager, Clinical Director) receive the full SBAR
const item = $input.first().json;
const m = item.metrics || {};
const p = item.predicted_arrivals || {};
const sbarRaw = item.sbar_drafted || '';
const approvedAt = item.approved_at ? new Date(item.approved_at).toLocaleString('en-GB') : new Date().toLocaleString('en-GB');
const auditId = item.audit ? item.audit.execution_id : 'N/A';

// Convert SBAR markdown to clean HTML (same approach as Build Approval Email)
const sbarRaw2 = sbarRaw.replace(/\*\*DRAFT SBAR[^\n]*\*\*\n?/gi, '').trim();
const sbarHtml = sbarRaw2
  .replace(/\*\*SITUATION:\*\*/gi, '<h4 style="color:#B71C1C;border-bottom:2px solid #FFCDD2;padding-bottom:6px;margin:16px 0 8px;">SITUATION</h4>')
  .replace(/\*\*BACKGROUND:\*\*/gi, '<h4 style="color:#B71C1C;border-bottom:2px solid #FFCDD2;padding-bottom:6px;margin:16px 0 8px;">BACKGROUND</h4>')
  .replace(/\*\*ASSESSMENT:\*\*/gi, '<h4 style="color:#B71C1C;border-bottom:2px solid #FFCDD2;padding-bottom:6px;margin:16px 0 8px;">ASSESSMENT</h4>')
  .replace(/\*\*RECOMMENDATION:\*\*/gi, '<h4 style="color:#B71C1C;border-bottom:2px solid #FFCDD2;padding-bottom:6px;margin:16px 0 8px;">RECOMMENDATION</h4>')
  .replace(/\n\n/g, '</p><p style="margin:6px 0;line-height:1.6;font-size:13px;color:#333;">')
  .replace(/\n(\d+\.)/g, '<br>$1')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\n(?!\n)/g, '<br>');

const emailDirectory = {
  'Site Manager': 'site.manager@rwh.nhs.uk',
  'Clinical Director': 'clinical.director@rwh.nhs.uk',
  'ICU Lead': 'icu.lead@rwh.nhs.uk',
  'Bed Management': 'bed.management@rwh.nhs.uk',
  'Surgical Team Lead': 'surgical.lead@rwh.nhs.uk',
  'Ambulance Liaison': 'ambulance.liaison@rwh.nhs.uk',
  'On-Call Coordinator': 'oncall.coordinator@rwh.nhs.uk',
};

const items = item.distributions.map(d => {
  const recipientEmail = emailDirectory[d.recipient] || 'haifaalarafa@gmail.com';
  const isSenior = ['Site Manager', 'Clinical Director'].includes(d.recipient);

  // SBAR section only for senior leadership
  let sbarSection = '';
  if (isSenior && sbarRaw) {
    sbarSection = '<div style="background:#FFF5F5;border:1px solid #FFCDD2;border-radius:6px;padding:20px;margin-bottom:24px;">'
      + '<p style="margin:0 0 6px;font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#B71C1C;font-weight:bold;">&#x1F4C4; Approved SBAR Briefing</p>'
      + '<p style="margin:6px 0;line-height:1.6;font-size:13px;color:#333;">' + sbarHtml + '</p>'
      + '</div>';
  }

  const emailHtml = '<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:0;background:#f4f4f4;">'
    + '<div style="background:#D32F2F;color:white;padding:20px 28px;border-radius:8px 8px 0 0;">'
    + '<h2 style="margin:0;font-size:20px;letter-spacing:0.5px;">&#x1F534; SYNTHELIX CRITICAL SURGE &#x2014; RED</h2>'
    + '<p style="margin:6px 0 0;opacity:0.9;font-size:13px;">Level 3 &#x2014; FULL ESCALATION | Capacity: ' + (m.capacity_ratio_pct || 'N/A') + '% | ' + approvedAt + '</p>'
    + '</div>'

    + '<div style="background:white;border:1px solid #ddd;border-top:none;padding:28px;border-radius:0 0 8px 8px;">'

    // Urgency banner
    + '<div style="background:#FFEBEE;border:2px solid #D32F2F;padding:14px 18px;margin-bottom:24px;border-radius:6px;text-align:center;">'
    + '<p style="margin:0;font-size:14px;font-weight:bold;color:#B71C1C;">&#x1F6A8; THIS IS A CRITICAL ESCALATION &#x2014; IMMEDIATE RESPONSE REQUIRED</p>'
    + '</div>'

    // Action box
    + '<div style="background:#FFEBEE;border-left:5px solid #D32F2F;padding:18px 20px;margin-bottom:24px;border-radius:0 6px 6px 0;">'
    + '<p style="margin:0 0 4px;font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#C62828;font-weight:bold;">Immediate Action Required</p>'
    + '<h3 style="margin:0 0 10px;color:#B71C1C;font-size:18px;">' + d.recipient + '</h3>'
    + '<p style="margin:0;font-size:15px;line-height:1.7;color:#333;font-weight:600;">' + d.action + '</p>'
    + '</div>'

    // SBAR (senior leadership only)
    + sbarSection

    // Metrics table
    + '<table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:24px;">'
    + '<tr style="background:#D32F2F;color:white;"><td colspan="2" style="padding:10px 14px;font-weight:bold;font-size:13px;text-transform:uppercase;letter-spacing:0.5px;border-radius:4px 4px 0 0;">Critical Metrics</td></tr>'
    + '<tr style="background:#FFEBEE;"><td style="padding:10px 14px;color:#555;border-bottom:1px solid #FFCDD2;">Predicted Arrivals</td><td style="padding:10px 14px;font-weight:bold;border-bottom:1px solid #FFCDD2;">' + (m.total_raw_arrivals || 0) + ' total (Weighted load: ' + (m.weighted_load || 0) + ')</td></tr>'
    + '<tr><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Cat 1 &#x2014; Resuscitation</td><td style="padding:10px 14px;font-weight:bold;color:#D32F2F;border-bottom:1px solid #f0f0f0;">' + (p.cat1 || 0) + '</td></tr>'
    + '<tr style="background:#fafafa;"><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Cat 2 &#x2014; Very Urgent</td><td style="padding:10px 14px;font-weight:bold;color:#D32F2F;border-bottom:1px solid #f0f0f0;">' + (p.cat2 || 0) + '</td></tr>'
    + '<tr><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Current ED Occupancy</td><td style="padding:10px 14px;font-weight:bold;color:#D32F2F;border-bottom:1px solid #f0f0f0;">' + (m.current_occupancy_pct || 0) + '%</td></tr>'
    + '<tr style="background:#fafafa;"><td style="padding:10px 14px;color:#555;border-bottom:1px solid #f0f0f0;">Resuscitation Spike</td><td style="padding:10px 14px;font-weight:bold;color:#D32F2F;border-bottom:1px solid #f0f0f0;">' + (m.resus_spike ? '&#x26A0;&#xFE0F; YES' : 'No') + '</td></tr>'
    + '<tr style="background:#FFEBEE;"><td style="padding:10px 14px;color:#555;">Priority Level</td><td style="padding:10px 14px;font-weight:bold;color:#D32F2F;font-size:15px;">' + d.priority + '</td></tr>'
    + '</table>'

    // Approval stamp
    + '<div style="background:#E8F5E9;border-left:4px solid #4CAF50;padding:12px 16px;margin-bottom:20px;border-radius:0 4px 4px 0;">'
    + '<p style="margin:0;font-size:13px;color:#2E7D32;">&#x2705; <strong>Approved by:</strong> ' + (item.approved_by || 'ED Charge Nurse') + ' at ' + approvedAt + '</p>'
    + '</div>'

    // Footer
    + '<p style="color:#aaa;font-size:11px;text-align:center;margin:0;padding-top:12px;border-top:1px solid #eee;">Synthelix Surge Co-pilot v3 | Audit ID: ' + auditId + ' | CRITICAL escalation approved by ED Charge Nurse before distribution</p>'
    + '</div>'
    + '</body></html>';

  return {
    json: {
      to: recipientEmail,
      subject: '\u{1F534} CRITICAL SURGE [RED] \u2014 IMMEDIATE Action: ' + d.recipient,
      html: emailHtml,
      recipient_role: d.recipient,
      action: d.action,
      priority: d.priority,
      surge_tier: 'RED',
      includes_sbar: isSenior,
    }
  };
});

return items;
